import time

def with_retries(fn, retries=3):
    last=None
    for i in range(retries):
        try:
            return fn()
        except TimeoutError as e:
            last=e
            time.sleep(0)  # backoff simbólico
    raise last

n={'c':0}
def flaky():
    n['c']+=1
    if n['c']<2:
        raise TimeoutError('x')
    return 'ok'
print(with_retries(flaky))

def process_row(row):
    if 'id' not in row:
        return {'status':'quarantine','reason':'missing id'}
    return {'status':'ok','id':row['id']}
